import{_ as e,o as l,c as t,a2 as r}from"./chunks/framework.m9rfQn3T.js";const u=JSON.parse('{"title":"我的第一个NFT","description":"","frontmatter":{"title":"我的第一个NFT","date":"2022-07-03T23:35:03.000Z","permalink":"/pages/9215dd598cf2f/","categories":["学习笔记","Web3"],"tags":[null]},"headers":[],"relativePath":"20.笔记/80.Web3/10.我的第一个NFT.md","filePath":"20.笔记/80.Web3/10.我的第一个NFT.md","lastUpdated":1782538095000}'),i={name:"20.笔记/80.Web3/10.我的第一个NFT.md"};function o(h,a,p,n,s,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703233530.png" alt="20220703233530"></p><blockquote><p>欢迎来到《我的第一个 NFT》</p></blockquote><ul><li><p>在这里你可以了解 Web3</p></li><li><p>在这里你可以铸造一个免费的 NFT</p></li><li><p>在这里你可以理解 NFT 的价值</p></li></ul><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703233734.png" alt="20220703233734"></p><p>&lt;!-- more --&gt;</p><h2 id="加密货币基础" tabindex="-1">加密货币基础 <a class="header-anchor" href="#加密货币基础" aria-label="Permalink to &quot;加密货币基础&quot;">​</a></h2><p>在介绍加密货币之前，我们不得不提到加密货币的底层技术——区块链。</p><h3 id="区块链是什么" tabindex="-1">区块链是什么？ <a class="header-anchor" href="#区块链是什么" aria-label="Permalink to &quot;区块链是什么？&quot;">​</a></h3><h4 id="这是一个区块" tabindex="-1">这是一个区块 <a class="header-anchor" href="#这是一个区块" aria-label="Permalink to &quot;这是一个区块&quot;">​</a></h4><ul><li>每一个区块包括两个部分：交易记录等一些信息, 和之前的区块摘要（哈希）。</li><li>每一个区块只有有限的存储容量。</li><li>每个区块会在一定时间内打包，例如大概 10 分钟打包生成一个。</li></ul><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703233845.png" alt="20220703233845"></p><h4 id="这是一条链" tabindex="-1">这是一条链 <a class="header-anchor" href="#这是一条链" aria-label="Permalink to &quot;这是一条链&quot;">​</a></h4><ul><li>一条链只可以链接两个区块。</li><li>只有一条链。</li><li>区块按照顺序依次串联。</li></ul><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703234922.png" alt="20220703234922"></p><h4 id="合并在一起就是-区块链" tabindex="-1">合并在一起就是： 区块链 <a class="header-anchor" href="#合并在一起就是-区块链" aria-label="Permalink to &quot;合并在一起就是： 区块链&quot;">​</a></h4><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703234006.png" alt="20220703234006"></p><h4 id="由此得出区块链特性" tabindex="-1">由此得出区块链特性 <a class="header-anchor" href="#由此得出区块链特性" aria-label="Permalink to &quot;由此得出区块链特性&quot;">​</a></h4><h5 id="不可篡改" tabindex="-1">不可篡改 <a class="header-anchor" href="#不可篡改" aria-label="Permalink to &quot;不可篡改&quot;">​</a></h5><p>你无法改变历史信息，因为每个区块包含了上一个区块的摘要并串联起来，如果你修改了历史的区块，你将必须修改后面的全部区块。</p><h5 id="公开透明、匿名" tabindex="-1">公开透明、匿名 <a class="header-anchor" href="#公开透明、匿名" aria-label="Permalink to &quot;公开透明、匿名&quot;">​</a></h5><p>在区块链上的信息全部公开透明。每个人都可以顺着区块和链找到历史上所有的记录来查看你的钱包余额。但是没人知道这是你的钱包。</p><h5 id="快速交易" tabindex="-1">快速交易 <a class="header-anchor" href="#快速交易" aria-label="Permalink to &quot;快速交易&quot;">​</a></h5><p>无论金额多少以及你在什么地方，只要你的交易记录被打包在区块链中，交易就自动完成。相比传统的跨国汇款非常快速便捷。</p><blockquote><p>那么如何来确保历史交易记录真的没有被篡改而且可信呢？</p></blockquote><p>分布式记账！</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703235101.png" alt="20220703235101"></p><p>一个区块链网络中有非常多的节点（矿机）来记账，每个节点都会记录完整的、相同的区块链信息！</p><p>有了分布式网络之后，区块链有了新特性</p><h5 id="去中心化" tabindex="-1">去中心化 <a class="header-anchor" href="#去中心化" aria-label="Permalink to &quot;去中心化&quot;">​</a></h5><p>区块链网络通常分布在全球，每个节点都将会存储一份相同的区块链数据。没有人能够控制全部的节点，因此这份区块链数据将会一直存在。</p><h5 id="真正的不可篡改" tabindex="-1">真正的不可篡改 <a class="header-anchor" href="#真正的不可篡改" aria-label="Permalink to &quot;真正的不可篡改&quot;">​</a></h5><p>区块链网络通常分布在全球，一个人控制大部分节点几乎不可能，因此即便有人修改了部分节点的区块链数据，只要被修改记录的节点不超过 51%，这个改动将不会被认可。</p><h3 id="什么是比特币-btc" tabindex="-1">什么是比特币（BTC）？ <a class="header-anchor" href="#什么是比特币-btc" aria-label="Permalink to &quot;什么是比特币（BTC）？&quot;">​</a></h3><blockquote><p>去中心化和分布式网络很好，可是为什么会有人愿意提供这项服务呢？</p></blockquote><p>因为他们可以因此得到奖励：比特币!</p><h4 id="节点可以得到奖励" tabindex="-1">节点可以得到奖励 <a class="header-anchor" href="#节点可以得到奖励" aria-label="Permalink to &quot;节点可以得到奖励&quot;">​</a></h4><p>网络节点服务提供商（以下简称为网络服务提供商）可以得到奖励。不同的网络服务提供商可以得到不同的代币奖励，比如：比特币。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703235154.png" alt="20220703235154"></p><h4 id="比特币具备了货币属性" tabindex="-1">比特币具备了货币属性 <a class="header-anchor" href="#比特币具备了货币属性" aria-label="Permalink to &quot;比特币具备了货币属性&quot;">​</a></h4><p>根据比特币的设计，它仅有有限的供应量，而且可以自由转账。因此具备了货币的特性，成为了加密货币。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703235218.png" alt="20220703235218"></p><h4 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h4><blockquote><p>比特币有什么价值？</p></blockquote><p>它具有货币的属性，按照白皮书的设计，不会通胀。同时根据区块链的特性它还具备以下特点：账户匿名、交易公开透明、不可篡改、完全在虚拟网络中，相比跨境转账结算等场景要方便许多。因此具备了一定的使用价值。</p><blockquote><p>为什么比特币会有如此高且不稳定的价格？</p></blockquote><p>它的价格由供需决定，与大白菜、股票、货币没有区别。只不过没有监管和限制，容易受到热点新闻的影响出现大幅度波动。</p><blockquote><p>区块链如何实现交易公开透明同时保护隐私并且匿名呢？</p></blockquote><p>在整个网络中，你的交易将通过一个随机生成的钱包地址完成，与这个钱包地址相关的交易等在网络上全部是公开透明的。匿名是因为别人不知道你跟这个钱包有关联。如果你在社交媒体发布过这个钱包地址，那么就可以将其跟你联系在一起。</p><blockquote><p>比特币有什么缺点？</p></blockquote><p>匿名和自由有利也有弊。弊端在于难以追踪和限制，所以经常被黑产利用，进行洗钱等违法犯罪活动。由于每打包一个区块需要约 10 分钟，因此也会影响交易的实时性。每个区块的存储数据也是有限的。不过，越来越多的新区块链技术正在优化和解决这些问题。</p><h3 id="区块链的核心组成部分" tabindex="-1">区块链的核心组成部分 <a class="header-anchor" href="#区块链的核心组成部分" aria-label="Permalink to &quot;区块链的核心组成部分&quot;">​</a></h3><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703235556.png" alt="20220703235556"></p><p>由上面区块链和比特币内容我们可以得知区块链由两个核心组成</p><h4 id="去中心化的网络和区块链" tabindex="-1">去中心化的网络和区块链 <a class="header-anchor" href="#去中心化的网络和区块链" aria-label="Permalink to &quot;去中心化的网络和区块链&quot;">​</a></h4><ul><li>区块链将会有一条链来记录全部的信息，这条链将存在对应的去中心化网络中。</li><li>去中心化的网络，将由无数节点提供服务来维持网络运行。这种操作称之为挖矿。</li></ul><h4 id="维持网络运行的代币激励" tabindex="-1">维持网络运行的代币激励 <a class="header-anchor" href="#维持网络运行的代币激励" aria-label="Permalink to &quot;维持网络运行的代币激励&quot;">​</a></h4><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703235722.png" alt="20220703235722"></p><ul><li>去中心化的网络由无数节点提供服务来维持网络运行，这种操作称之为挖矿。维持这些服务的人一般称之为矿工。矿工们维持网络运行需要奖励，就像你工作需要工资，在区块链中对矿工的奖励一般是代币，你经常听说的 Gas Fee 就是矿工们的「工资」。</li><li>你使用这个网络进行交易、转账、铸造 NFT 等等，均需要支付代币。如果你没有代币又想使用这个区块链网络服务，则需要进行代币之间交换或者法币交换。</li></ul><h4 id="一条区块链如何运转起来呢" tabindex="-1">一条区块链如何运转起来呢 <a class="header-anchor" href="#一条区块链如何运转起来呢" aria-label="Permalink to &quot;一条区块链如何运转起来呢&quot;">​</a></h4><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220703235824.png" alt="20220703235824"></p><p>由于区块链结点的存在，让区块链技术与特性得以维持，从而聚集了大量的开发者基于此来研发应用，有了项目就能让用户聚集与活跃，由此产生的交易代币滋养了区块链结点。</p>',61)])])}const g=e(i,[["render",o]]);export{u as __pageData,g as default};
